// Test regex against both patterns
const regex = /\\{prompt:\([\\s\\S]+\)/;

// Pattern 1: google imagegen
const msg1 = 'call:google:imagegen{prompt: a beautiful landscape with mountains and sunset}';
const match1 = msg1.match\(regex\);
console.log\('Pattern 1 \(google:imagegen\):'\);
console.log\('  Input:', msg1\);
console.log\('  Match:', match1 ? match1[1] : 'NO MATCH'\);
console.log\(''\);

// Pattern 2: dalle
const msg2 = 'call:dalle{prompt: a cat sitting on a chair}';
const match2 = msg2.match\(regex\);
console.log\('Pattern 2 \(dalle\):'\);
console.log\('  Input:', msg2\);
console.log\('  Match:', match2 ? match2[1] : 'NO MATCH'\);
console.log\(''\);

// Pattern 3: with trailing braces and newlines
const msg3 = 'call:google:imagegen{prompt: test prompt with trailing braces }}';
const match3 = msg3.match\(regex\);
console.log\('Pattern 3 \(with trailing braces\):'\);
console.log\('  Input:', msg3\);
console.log\('  Raw match:', match3 ? match3[1] : 'NO MATCH'\);
if \(match3\) {
  const cleaned = match3[1].trim\(\).replace\(/\\}?\\s*$/, ''\).trim\(\);
  console.log\('  After cleanup:', cleaned\);
}
console.log\(''\);

// Pattern 4: with newlines
const msg4 = 'call:google:imagegen{prompt: test prompt\\nwith newlines\\nand more text}';
const match4 = msg4.match\(regex\);
console.log\('Pattern 4 \(with newlines\):'\);
console.log\('  Input:', msg4\);
console.log\('  Raw match:', match4 ? match4[1].substring\(0, 50\) : 'NO MATCH'\);
if \(match4\) {
  const cleaned = match4[1].trim\(\).replace\(/\\}?\\s*$/, ''\).trim\(\);
  console.log\('  After cleanup \(first 50 chars\):', cleaned.substring\(0, 50\)\);
}
")

